var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"우와아......","JPN":"うわあ……","ENG":"Whoa...","TWN":"哇啊……"},"stage":{"bg":"COUNTERSIDE_BASE","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"저 건물 좀 보세요. 저희가 봤던 유적이랑은 많이 달라요.","JPN":"あの建物を見てください。私たちが見た遺跡とはかなり違いますね。","ENG":"Check out that building. It's nothing like the ruins we saw.","TWN":"快看那個建築，跟我們看到的遺跡非常不同。"},"stage":{"bg":"COUNTERSIDE_BASE","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L5_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"그래...... 그런 것 같군.","JPN":"そう……みたいだな。","ENG":"You're right... So it is.","TWN":"是啊……好像是呢。"},"stage":{"bg":"COUNTERSIDE_BASE","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"언니, 고집 부리지 말고 저한테 기대세요. 부축해 드릴게요.","JPN":"リタお姉ちゃん、意地を張らないで私にもたれかかってください。支えますよ。","ENG":"Stop being so stubborn and lean on me, Rita. I'll prop you up.","TWN":"姐姐，別固執了，靠著我。我來扶你。"},"stage":{"bg":"COUNTERSIDE_BASE","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"아까부터 자꾸 제대로 못 걷고 휘청거리잖아요.","JPN":"さっきからちゃんと歩けなくて、ふらついているんでしょう。","ENG":"You keep stumbling.","TWN":"從剛才開始你走路一直不穩，搖搖晃晃的。"},"stage":{"bg":"COUNTERSIDE_BASE","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"잔소리는...... 아직 버틸 만하니까 네 몸이나 챙겨.","JPN":"うるさい……まだ耐えられる程度だし、自分のことを気にしろ。","ENG":"There you go nagging me again... I can walk just fine on my own. Take care of yourself.","TWN":"囉嗦……我還能堅持，你照顧好自己。"},"stage":{"bg":"COUNTERSIDE_BASE","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L10_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_DRONE","text":{"KOREA":"흐음.","JPN":"ふむ。","ENG":"Hmm...","TWN":"呃嗯。"},"stage":{"bg":"COUNTERSIDE_BASE","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_DRONE","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_DRONE","text":{"KOREA":"건축 양식만 보면, 대정화 전쟁 직후 탐사 목적으로 건설된 주둔지로 보입니다.","JPN":"建築様式を見る限り、大浄化戦争直後に探査目的で建設された駐屯地と思われます。","ENG":"Based on the architecture, this appears to be an exploration outpost constructed right after the Grand Purification War.","TWN":"僅從建築樣式來看，這裡就是淨化之戰結束後以探索為目的建設的駐紮地。"},"stage":{"bg":"COUNTERSIDE_BASE","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_DRONE","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"주둔지요? 이면세계까지 와서 저렇게 커다란 건물을 세웠다고요?","JPN":"駐屯地ですか？　裏世界まで来てあんなに大きな建物を建てたということですか？","ENG":"An outpost? Why would they build such a huge building all the way here on the Counterside?","TWN":"駐紮地？來到異界建造了這麼雄偉的建築？"},"stage":{"bg":"COUNTERSIDE_BASE","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L15_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"이면세계에 대해 뭘 모를 때 저질렀던 바보짓이야.","JPN":"裏世界について知識がなかった時代にやらかしたことだ。","ENG":"Those fools didn't know crap about the Counterside back then.","TWN":"是不瞭解異界的時候做下的傻事。"},"stage":{"bg":"COUNTERSIDE_BASE","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"저런 거창한 시설도 시간이 지나면 침식파가 침투하게 되는데 말이지.","JPN":"あんな立派な施設でも、時間が経つと侵食波が浸透してしまうからな。","ENG":"Even a sturdy building like that will succumb to Corruption Rays given enough time.","TWN":"因為那樣宏偉的設施也會隨著時間的推移被侵蝕波滲透。"},"stage":{"bg":"COUNTERSIDE_BASE","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_DRONE","text":{"KOREA":"리타 말대로입니다. 그렇지 않았으면 번거롭게 함선으로 왕래할 필요도 없었겠죠.","JPN":"リタの言うとおりです。そうでなければわざわざ艦船に乗って往来する必要もなかったでしょう。","ENG":"It's as Rita said. Otherwise, we wouldn't need to bother relying on such cumbersome ships out here.","TWN":"麗塔說的沒錯。若非如此，也不必那麼麻煩用艦船來往了。"},"stage":{"bg":"COUNTERSIDE_BASE","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_DRONE","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"그러면...... 지금은 저 건물 안에 침식체가 있을지도 모르겠네요?","JPN":"ということは……今はあの建物の中に侵食体がいるかもしれないってことですか？","ENG":"So... I guess that means the building might be crawling with C.O.s?","TWN":"那……現在那座建築裡說不定有侵蝕體吧？"},"stage":{"bg":"COUNTERSIDE_BASE","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L22_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"없는 게 더 이상하겠지.","JPN":"いないほうがおかしいだろ。","ENG":"It'd be weirder if it wasn't.","TWN":"沒有才奇怪。"},"stage":{"bg":"COUNTERSIDE_BASE","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"그래도 확인해 볼 만한 가치는 있어.","JPN":"でも確かめてみる価値はある。","ENG":"Still, it's worth checking out.","TWN":"但也應該確認一下。"},"stage":{"bg":"COUNTERSIDE_BASE","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L24_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"통신 설비만 살아 있다면...... 온 이면세계에 퍼지게 구조 요청을 보낼 수 있을 거야.","JPN":"通信設備さえ動いていれば……裏世界全域に救助要請を送ることができる。","ENG":"If the communication equipment still functions... We should be able to send an SOS all over the Counterside.","TWN":"只要還有通信設備……就可以發出覆蓋整個異界的求救信號。"},"stage":{"bg":"COUNTERSIDE_BASE","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"그렇네요!","JPN":"よかった！","ENG":"You're right!","TWN":"是啊！"},"stage":{"bg":"COUNTERSIDE_BASE","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"그럼 언니는 안전한 곳에 있으세요! 여기서부터는 제가 앞장 설게요!","JPN":"じゃあ、リタお姉ちゃんは安全な場所にいてください！　私が動きます！","ENG":"You should stay here, where it's safe! I'll lead the way from here!","TWN":"那姐姐你就待在安全的地方吧！從這裡開始，我來打頭陣！"},"stage":{"bg":"COUNTERSIDE_BASE","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}}]`);export{e as default};